import React, { useEffect, useState } from "react";
import API from "../../api/api";

const Projects = () => {
  const [proposals, setProposals]   = useState([]);
  const [loading, setLoading]       = useState(true);
  const [modal, setModal]           = useState(null);   // { proposal_id, project_id, project_title }
  const [form, setForm]             = useState({ github_link: "", live_link: "", note: "" });
  const [submitting, setSubmitting] = useState(false);
  const [successMsg, setSuccessMsg] = useState("");
  const [submitted, setSubmitted]   = useState({}); // { [proposal_id]: true }

  useEffect(() => {
    const load = async () => {
      try {
        const res = await API.get("/proposals/my");
        const data = res.data || [];
        setProposals(data);

        // Check which proposals already have submissions
        const acceptedIds = data
          .filter(p => p.status === "accepted")
          .map(p => p.id);

        const checks = {};
        await Promise.all(
          acceptedIds.map(async (id) => {
            try {
              const r = await API.get(`/submissions/proposal/${id}`);
              if (r.data && r.data.length > 0) checks[id] = r.data[0];
            } catch {}
          })
        );
        setSubmitted(checks);
      } catch (err) {
        console.error(err);
      }
      setLoading(false);
    };
    load();
  }, []);

  const openModal = (proposal) => {
    const existing = submitted[proposal.id];
    setForm({
      github_link: existing?.github_link || "",
      live_link:   existing?.live_link   || "",
      note:        existing?.note        || "",
    });
    setModal({
      proposal_id:   proposal.id,
      project_id:    proposal.project_id,
      project_title: proposal.project_title,
    });
  };

  const handleSubmit = async () => {
    setSubmitting(true);
    try {
      await API.post("/submissions", {
        proposal_id: modal.proposal_id,
        project_id:  modal.project_id,
        github_link: form.github_link,
        live_link:   form.live_link,
        note:        form.note,
      });
      setSubmitted(prev => ({
        ...prev,
        [modal.proposal_id]: {
          github_link: form.github_link,
          live_link:   form.live_link,
          note:        form.note,
        }
      }));
      setSuccessMsg("Work submitted successfully!");
      setTimeout(() => {
        setSuccessMsg("");
        setModal(null);
      }, 1500);
    } catch (err) {
      console.error(err);
      alert("Submission failed. Please try again.");
    }
    setSubmitting(false);
  };

  const statusStyle = (s) => {
    if (s === "accepted") return "bg-green-100 text-green-700 border-green-200";
    if (s === "rejected") return "bg-red-100 text-red-600 border-red-200";
    return "bg-yellow-100 text-yellow-700 border-yellow-200";
  };

  if (loading) return <div className="text-center py-16 text-gray-400">Loading...</div>;

  return (
    <div className="bg-gray-50 min-h-screen p-8">
      <div className="max-w-4xl mx-auto">

        <h1 className="text-2xl font-bold text-gray-800 mb-1">My Projects</h1>
        <p className="text-gray-500 text-sm mb-6">Projects where your proposal was accepted</p>

        {proposals.filter(p => p.status === "accepted").length === 0 ? (
          <div className="bg-white rounded-xl p-12 text-center shadow-sm border border-gray-100">
            <div className="text-5xl mb-3">📁</div>
            <p className="text-gray-500">No accepted projects yet.</p>
          </div>
        ) : (
          <div className="space-y-4">
            {proposals
              .filter(p => p.status === "accepted")
              .map((p) => {
                const sub = submitted[p.id];
                return (
                  <div key={p.id} className="bg-white rounded-xl shadow-sm border border-gray-100 p-5">

                    {/* TOP ROW */}
                    <div className="flex justify-between items-start mb-3">
                      <div>
                        <h3 className="font-bold text-gray-800 text-lg">{p.project_title}</h3>
                        <p className="text-gray-500 text-sm mt-0.5">{p.message}</p>
                      </div>
                      <span className={`px-3 py-1 rounded-full text-xs font-semibold border capitalize ${statusStyle(p.status)}`}>
                        ✓ {p.status}
                      </span>
                    </div>

                    {/* BID INFO */}
                    <div className="flex gap-5 text-sm mb-4 pt-3 border-t border-gray-100">
                      <span className="text-gray-500">Project Budget: <strong className="text-gray-700">₹{p.project_budget || p.budget}</strong></span>
                      <span className="text-teal-600 font-bold">Your Bid: ₹{p.bid}</span>
                    </div>

                    {/* SUBMISSION STATUS */}
                    {sub ? (
                      <div className="bg-teal-50 border border-teal-200 rounded-lg p-4 mb-3">
                        <p className="text-teal-700 font-semibold text-sm mb-2">✅ Work Submitted</p>
                        <div className="space-y-1 text-sm">
                          {sub.github_link && (
                            <div className="flex items-center gap-2">
                              <span className="text-gray-500">GitHub:</span>
                              <a href={sub.github_link} target="_blank" rel="noreferrer"
                                className="text-blue-600 hover:underline truncate">{sub.github_link}</a>
                            </div>
                          )}
                          {sub.live_link && (
                            <div className="flex items-center gap-2">
                              <span className="text-gray-500">Live:</span>
                              <a href={sub.live_link} target="_blank" rel="noreferrer"
                                className="text-blue-600 hover:underline truncate">{sub.live_link}</a>
                            </div>
                          )}
                          {sub.note && <p className="text-gray-600 mt-1">📝 {sub.note}</p>}
                        </div>
                      </div>
                    ) : null}

                    {/* SUBMIT BUTTON */}
                    <button
                      onClick={() => openModal(p)}
                      className={`px-5 py-2 rounded-lg text-sm font-medium transition ${
                        sub
                          ? "bg-gray-100 hover:bg-gray-200 text-gray-700"
                          : "bg-teal-600 hover:bg-teal-700 text-white"
                      }`}
                    >
                      {sub ? "✏️ Update Submission" : "🚀 Submit Work"}
                    </button>

                  </div>
                );
              })}
          </div>
        )}

      </div>

      {/* ===== MODAL ===== */}
      {modal && (
        <div className="fixed inset-0 bg-black bg-opacity-40 flex items-center justify-center z-50 px-4">
          <div className="bg-white rounded-2xl shadow-xl w-full max-w-md p-6">

            {successMsg ? (
              <div className="text-center py-8">
                <div className="text-5xl mb-3">🎉</div>
                <p className="text-green-600 font-bold text-lg">{successMsg}</p>
              </div>
            ) : (
              <>
                <div className="flex justify-between items-center mb-5">
                  <div>
                    <h2 className="text-lg font-bold text-gray-800">Submit Your Work</h2>
                    <p className="text-sm text-gray-500 truncate">{modal.project_title}</p>
                  </div>
                  <button onClick={() => setModal(null)}
                    className="text-gray-400 hover:text-gray-600 text-xl font-bold">✕</button>
                </div>

                {/* GITHUB LINK */}
                <div className="mb-4">
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    🔗 GitHub Link
                  </label>
                  <input
                    type="url"
                    value={form.github_link}
                    onChange={e => setForm({ ...form, github_link: e.target.value })}
                    placeholder="https://github.com/username/repo"
                    className="w-full border border-gray-300 px-3 py-2 rounded-lg text-sm focus:ring-2 focus:ring-teal-500 outline-none"
                  />
                </div>

                {/* LIVE LINK */}
                <div className="mb-4">
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    🌐 Live Link <span className="text-gray-400">(optional)</span>
                  </label>
                  <input
                    type="url"
                    value={form.live_link}
                    onChange={e => setForm({ ...form, live_link: e.target.value })}
                    placeholder="https://yourproject.vercel.app"
                    className="w-full border border-gray-300 px-3 py-2 rounded-lg text-sm focus:ring-2 focus:ring-teal-500 outline-none"
                  />
                </div>

                {/* NOTE */}
                <div className="mb-6">
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    📝 Note <span className="text-gray-400">(optional)</span>
                  </label>
                  <textarea
                    value={form.note}
                    onChange={e => setForm({ ...form, note: e.target.value })}
                    rows={3}
                    placeholder="Any notes for the client about your submission..."
                    className="w-full border border-gray-300 px-3 py-2 rounded-lg text-sm focus:ring-2 focus:ring-teal-500 outline-none resize-none"
                  />
                </div>

                <div className="flex gap-3">
                  <button onClick={handleSubmit} disabled={submitting || !form.github_link}
                    className="flex-1 bg-teal-600 hover:bg-teal-700 text-white py-2 rounded-lg text-sm font-medium transition disabled:opacity-50">
                    {submitting ? "Submitting..." : "Submit Work"}
                  </button>
                  <button onClick={() => setModal(null)}
                    className="px-5 py-2 rounded-lg text-sm font-medium bg-gray-100 hover:bg-gray-200 text-gray-700 transition">
                    Cancel
                  </button>
                </div>
              </>
            )}
          </div>
        </div>
      )}

    </div>
  );
};

export default Projects;
